#include "interface.h"\n#include <simdutf.h>\n#include <vector>\n#include <cstdint>\n\nnamespace {\nuint64_t fnv1a_checksum(const char16_t* data, size_t len) {\n    uint64_t hash = 1469598103934665603ULL;\n    for (size_t i = 0; i < len; ++i) {\n        hash ^= static_cast<uint64_t>(data[i]);\n        hash *= 1099511628211ULL;\n    }\n    return hash;\n}\n}  // namespace\n\nuint64_t transcode_checksum(const std::string& input) {\n    std::vector<char16_t> output(input.size());\n    size_t output_len = simdutf::convert_utf8_to_utf16le(input.data(), input.size(), output.data());\n    return fnv1a_checksum(output.data(), output_len);\n}\n